-- Migration 014: Web-first pivot
-- Customer personal QR codes, welcome bonus, n8n AI settings, POS validation

-- 1. Customer personal QR codes for redemption scanning
create table public.customer_qr_codes (
  id uuid primary key default gen_random_uuid(),
  customer_id uuid references public.customers(id) on delete cascade not null,
  qr_secret text not null default replace(gen_random_uuid()::text || gen_random_uuid()::text, '-', ''),
  is_active boolean not null default true,
  created_at timestamptz not null default now(),
  unique(customer_id)
);

create index idx_customer_qr_customer on public.customer_qr_codes(customer_id);
create index idx_customer_qr_secret on public.customer_qr_codes(qr_secret);

alter table public.customer_qr_codes enable row level security;

create policy "Customer QR: own access"
  on public.customer_qr_codes for all
  using (customer_id = auth.uid());

create policy "Customer QR: merchant read via card"
  on public.customer_qr_codes for select
  using (customer_id in (
    select cc.customer_id from customer_cards cc
    join loyalty_programs lp on cc.program_id = lp.id
    join merchants m on lp.merchant_id = m.id
    where m.user_id = auth.uid()
  ));

-- 2. Welcome bonus config on loyalty programs
alter table public.loyalty_programs
  add column if not exists welcome_bonus_stamps int default 0,
  add column if not exists welcome_bonus_points numeric(10,2) default 0;

-- 3. Extend transaction validation methods to include api and pos
alter table public.transactions
  drop constraint if exists transactions_validated_by_check;
alter table public.transactions
  add constraint transactions_validated_by_check
  check (validated_by in ('qr', 'nfc', 'manual', 'api', 'pos'));

-- 4. n8n automation settings per merchant
alter table public.merchants
  add column if not exists ai_campaigns_mode text not null default 'manual'
    check (ai_campaigns_mode in ('manual', 'assisted', 'autonomous')),
  add column if not exists max_push_per_week int not null default 3;

-- 5. Function: create customer with personal QR code
create or replace function public.create_customer_with_qr(
  p_customer_id uuid,
  p_email text,
  p_name text default null
) returns json as $$
declare
  v_qr record;
begin
  insert into public.customers (id, email, name)
  values (p_customer_id, p_email, p_name)
  on conflict (id) do update set
    email = excluded.email,
    name = coalesce(excluded.name, customers.name),
    updated_at = now();

  insert into public.customer_qr_codes (customer_id)
  values (p_customer_id)
  on conflict (customer_id) do nothing;

  select * into v_qr from public.customer_qr_codes where customer_id = p_customer_id;

  return json_build_object(
    'customer_id', p_customer_id,
    'qr_id', v_qr.id,
    'qr_secret', v_qr.qr_secret
  );
end;
$$ language plpgsql security definer;

-- 6. Function: validate customer QR (merchant scans customer)
create or replace function public.validate_customer_qr(
  p_qr_secret text,
  p_merchant_user_id uuid
) returns json as $$
declare
  v_customer_id uuid;
  v_cards json;
begin
  select customer_id into v_customer_id
  from public.customer_qr_codes
  where qr_secret = p_qr_secret and is_active = true;

  if v_customer_id is null then
    return json_build_object('error', 'Invalid or inactive QR code');
  end if;

  select json_agg(row_to_json(t)) into v_cards
  from (
    select cc.id as card_id, cc.current_stamps, cc.current_points, cc.tier,
           lp.id as program_id, lp.name as program_name, lp.type as program_type,
           lp.stamp_goal,
           (select json_agg(row_to_json(r))
            from rewards r
            where r.program_id = lp.id
              and r.is_active = true
              and (
                (lp.type = 'stamp' and r.stamps_required <= cc.current_stamps)
                or (lp.type = 'points' and r.points_cost <= cc.current_points)
              )
           ) as available_rewards
    from customer_cards cc
    join loyalty_programs lp on cc.program_id = lp.id
    join merchants m on lp.merchant_id = m.id
    where cc.customer_id = v_customer_id
      and m.user_id = p_merchant_user_id
  ) t;

  return json_build_object(
    'customer_id', v_customer_id,
    'cards', coalesce(v_cards, '[]'::json)
  );
end;
$$ language plpgsql security definer;
```

